import{_ as a,o as t,c as d,a3 as o}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Tenant API v1 — Calendar","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant API v1 — Calendar | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/tenant-v1-calendar"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant API v1 — Calendar | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/tenant-v1-calendar"}]]},"headers":[],"relativePath":"api/tenant-v1-calendar.md","filePath":"api/tenant-v1-calendar.md","lastUpdated":1784733008000}'),c={name:"api/tenant-v1-calendar.md"};function n(r,e,i,l,s,p){return t(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="tenant-api-v1-—-calendar" tabindex="-1">Tenant API v1 — Calendar <a class="header-anchor" href="#tenant-api-v1-—-calendar" aria-label="Permalink to &quot;Tenant API v1 — Calendar&quot;">​</a></h1><p>Base path: <code>/api/tenant/v1</code></p><p>Middleware: <code>auth:tenant-api</code>, <code>tenant.user</code>, <code>verified</code>, <code>module:calendar</code>, plus <code>can:calendar.*</code> / policies.</p><p>Visibility: without <code>calendar.view_all</code>, only events where <code>organizer_id</code> is the current user. No calendar assignment — <code>organizer_id</code> and <code>assignee_id</code> are prohibited on write payloads.</p><h2 id="upcoming" tabindex="-1">Upcoming <a class="header-anchor" href="#upcoming" aria-label="Permalink to &quot;Upcoming&quot;">​</a></h2><h3 id="get-calendar-upcoming" tabindex="-1">GET <code>/calendar/upcoming</code> <a class="header-anchor" href="#get-calendar-upcoming" aria-label="Permalink to &quot;GET `/calendar/upcoming`&quot;">​</a></h3><p>Query: <code>limit</code> (1–25, default 8). Scheduled events with <code>starts_at &gt;= now()</code>, visibility-scoped.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><h3 id="get-calendar-events" tabindex="-1">GET <code>/calendar/events</code> <a class="header-anchor" href="#get-calendar-events" aria-label="Permalink to &quot;GET `/calendar/events`&quot;">​</a></h3><p>Query: <code>search</code>, <code>status</code>, <code>from</code>, <code>to</code>, <code>trashed</code>, <code>sort</code> (default <code>starts_at</code>), <code>direction</code> (default <code>asc</code>), <code>page</code>, <code>per_page</code>, <code>paginate</code> (<code>0</code>/<code>false</code> returns a non-paginated range collection when <code>from</code>+<code>to</code> are set).</p><h3 id="post-calendar-events" tabindex="-1">POST <code>/calendar/events</code> <a class="header-anchor" href="#post-calendar-events" aria-label="Permalink to &quot;POST `/calendar/events`&quot;">​</a></h3><p>Body: <code>title</code> (required), <code>description</code>, <code>starts_at</code>, <code>ends_at</code> (<code>after_or_equal:starts_at</code>), <code>all_day</code>, <code>timezone</code>, <code>color</code>.</p><p>Sets <code>organizer_id</code> to the authenticated user. Status <code>scheduled</code>, source <code>manual</code>.</p><h3 id="get-calendar-events-id" tabindex="-1">GET <code>/calendar/events/{id}</code> <a class="header-anchor" href="#get-calendar-events-id" aria-label="Permalink to &quot;GET `/calendar/events/{id}`&quot;">​</a></h3><h3 id="put-calendar-events-id" tabindex="-1">PUT <code>/calendar/events/{id}</code> <a class="header-anchor" href="#put-calendar-events-id" aria-label="Permalink to &quot;PUT `/calendar/events/{id}`&quot;">​</a></h3><p>Same writable fields as create (partial). Organizer/source/status fields prohibited.</p><p>Used by the SPA form and by Week/Day <strong>drag-and-drop</strong> reschedule (<code>starts_at</code> + <code>ends_at</code> only).</p><h3 id="post-calendar-events-id-cancel" tabindex="-1">POST <code>/calendar/events/{id}/cancel</code> <a class="header-anchor" href="#post-calendar-events-id-cancel" aria-label="Permalink to &quot;POST `/calendar/events/{id}/cancel`&quot;">​</a></h3><p>Sets <code>status=cancelled</code> and <code>cancelled_at</code>.</p><h3 id="delete-calendar-events-id" tabindex="-1">DELETE <code>/calendar/events/{id}</code> <a class="header-anchor" href="#delete-calendar-events-id" aria-label="Permalink to &quot;DELETE `/calendar/events/{id}`&quot;">​</a></h3><p>Soft delete.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p><code>calendar.view</code> · <code>create</code> · <code>update</code> · <code>delete</code> · <code>view_all</code></p>',23)])])}const m=a(c,[["render",n]]);export{u as __pageData,m as default};
